shapes.frame_eqs_str:
speed1 = (bass/5000 + mid/10000 + treb/10000);
speed2 = (mid/5000 + bass/10000 + treb/10000);
speed3 = (treb/5000 + bass/10000 + mid/10000);
r = r + 0.5*sin(time*speed1*16);
g = g + 0.5*sin(time*speed2*16);
b = b + 0.5*sin(time*speed3*16);

warp:
shader_body { 
 vec4 tmpvar_1;
 tmpvar_1.w = 1.0;
 tmpvar_1.xyz = (texture (sampler_main, uv).xyz * 0.9);
 ret = tmpvar_1.xyz;
}

comp:
shader_body { 
 vec3 ret_1;
 ret_1 = (vec3((texture (sampler_noise_lq, (uv * 4.0)).x * 0.3)) - dot ((
   (texture (sampler_blur1, (uv - 0.1)).xyz * scale1)
  + bias1), vec3(0.32, 0.49, 0.29)));
 ret_1 = (ret_1 + texture (sampler_main, uv).xyz);
 vec4 tmpvar_2;
 tmpvar_2.w = 1.0;
 tmpvar_2.xyz = ret_1;
 ret = tmpvar_2.xyz;
}
